CREATE TABLE `reviews` (`id` bigint unsigned NOT NULL AUTO_INCREMENT, `user_id` int NOT NULL, `order_sn` varchar(64) NOT NULL, `goods_id` int NOT NULL, `rating` tinyint NOT NULL, `content` varchar(2000) NOT NULL, `status` varchar(16) NOT NULL DEFAULT 'PENDING', `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updated_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE KEY `uk_review_purchase` (`user_id`,`order_sn`,`goods_id`), KEY `idx_review_goods_status` (`goods_id`,`status`,`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `review_appends` (`id` bigint unsigned NOT NULL AUTO_INCREMENT, `review_id` bigint unsigned NOT NULL, `content` varchar(2000) NOT NULL, `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE KEY `uk_review_append` (`review_id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `review_replies` (`id` bigint unsigned NOT NULL AUTO_INCREMENT, `review_id` bigint unsigned NOT NULL, `actor_user_id` int NOT NULL, `content` varchar(2000) NOT NULL, `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE KEY `uk_review_reply` (`review_id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `review_audit_logs` (`id` bigint unsigned NOT NULL AUTO_INCREMENT, `review_id` bigint unsigned NOT NULL, `actor_user_id` int NOT NULL, `action` varchar(32) NOT NULL, `from_status` varchar(16) NOT NULL DEFAULT '', `to_status` varchar(16) NOT NULL DEFAULT '', `request_id` varchar(128) NOT NULL, `reason` varchar(255) NOT NULL DEFAULT '', `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), KEY `idx_review_audit_review` (`review_id`,`created_at`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `review_outbox_events` (`id` bigint unsigned NOT NULL AUTO_INCREMENT, `event_key` varchar(128) NOT NULL, `goods_id` int NOT NULL, `event_type` varchar(32) NOT NULL, `status` varchar(16) NOT NULL DEFAULT 'PENDING', `retry_count` int NOT NULL DEFAULT 0, `next_attempt_at` bigint NOT NULL DEFAULT 0, `last_error` varchar(500) NOT NULL DEFAULT '', `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `completed_at` datetime(3) NULL, PRIMARY KEY (`id`), UNIQUE KEY `uk_review_outbox_event` (`event_key`), KEY `idx_review_outbox_pending` (`status`,`next_attempt_at`,`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE `review_product_ratings` (`goods_id` int NOT NULL, `approved_count` bigint NOT NULL DEFAULT 0, `rating_sum` bigint NOT NULL DEFAULT 0, `average_milli` int NOT NULL DEFAULT 0, `rebuilt_at` datetime(3) NOT NULL, PRIMARY KEY (`goods_id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
